#!/usr/bin/env python3
"""Regenerate days.js from the predictions/ folder.

Run from any directory; uses repo root resolution.
"""
from pathlib import Path
import json

ROOT = Path(__file__).resolve().parent.parent
PRED = ROOT / 'predictions'

days = sorted([p.stem for p in PRED.glob('*.json')], reverse=True)
out = ROOT / 'days.js'
out.write_text(
    '// auto-generated by build_index.py — do not edit by hand\n'
    f'window.STATSLAP_DAYS = {json.dumps(days)};\n'
)
print(f'Wrote {len(days)} days to {out.relative_to(ROOT)}')
